#include "offload_benchmark.h"

#include <doca_dev.h>
#include <doca_dpa.h>
#include <doca_error.h>

#include <cstdio>
#include <cstdlib>
#include <cstring>

/* Generated by existing DPUMesh build_dpacc.sh (--app-name=DPU_mesh_dpa_app) */
extern struct doca_dpa_app *DPU_mesh_dpa_app;

struct BenchCli {
    const char *pci_addr;
    uint32_t warmup;
    uint32_t iters;
    uint32_t submit_batch;
    uint32_t name_len;
    uint32_t scores_count;
    uint32_t score_seed;
    uint32_t max_batch;
};

static void print_usage(const char *prog)
{
    std::fprintf(stderr,
                 "Usage: %s --pci <BDF> [--iters N] [--warmup N] [--submit-batch N] [--name-len N] [--scores N] [--seed N] [--batch N]\\n",
                 prog);
}

static bool parse_u32(const char *s, uint32_t *out)
{
    char *end = nullptr;
    unsigned long v = std::strtoul(s, &end, 10);
    if (s[0] == '\0' || end == nullptr || *end != '\0' || v > 0xffffffffUL)
        return false;
    *out = static_cast<uint32_t>(v);
    return true;
}

static bool parse_cli(int argc, char **argv, BenchCli *cli)
{
    *cli = BenchCli{
        .pci_addr = nullptr,
        .warmup = 100,
        .iters = 5000,
        .submit_batch = 1,
        .name_len = 64,
        .scores_count = 128,
        .score_seed = 1,
        .max_batch = 64,
    };

    for (int i = 1; i < argc; ++i) {
        if (std::strcmp(argv[i], "--pci") == 0 && i + 1 < argc) {
            cli->pci_addr = argv[++i];
        } else if (std::strcmp(argv[i], "--iters") == 0 && i + 1 < argc) {
            if (!parse_u32(argv[++i], &cli->iters))
                return false;
        } else if (std::strcmp(argv[i], "--warmup") == 0 && i + 1 < argc) {
            if (!parse_u32(argv[++i], &cli->warmup))
                return false;
        } else if (std::strcmp(argv[i], "--submit-batch") == 0 && i + 1 < argc) {
            if (!parse_u32(argv[++i], &cli->submit_batch))
                return false;
        } else if (std::strcmp(argv[i], "--name-len") == 0 && i + 1 < argc) {
            if (!parse_u32(argv[++i], &cli->name_len))
                return false;
        } else if (std::strcmp(argv[i], "--scores") == 0 && i + 1 < argc) {
            if (!parse_u32(argv[++i], &cli->scores_count))
                return false;
        } else if (std::strcmp(argv[i], "--seed") == 0 && i + 1 < argc) {
            if (!parse_u32(argv[++i], &cli->score_seed))
                return false;
        } else if (std::strcmp(argv[i], "--batch") == 0 && i + 1 < argc) {
            if (!parse_u32(argv[++i], &cli->max_batch))
                return false;
        } else {
            return false;
        }
    }

    return cli->pci_addr != nullptr;
}

static doca_error_t open_dev_by_pci(const char *pci_addr, struct doca_dev **dev_out)
{
    struct doca_devinfo **dev_list = nullptr;
    uint32_t nb_devs = 0;
    uint8_t is_equal = 0;
    doca_error_t ret;

    *dev_out = nullptr;

    ret = doca_devinfo_create_list(&dev_list, &nb_devs);
    if (ret != DOCA_SUCCESS)
        return ret;

    for (uint32_t i = 0; i < nb_devs; ++i) {
        ret = doca_devinfo_is_equal_pci_addr(dev_list[i], pci_addr, &is_equal);
        if (ret == DOCA_SUCCESS && is_equal) {
            ret = doca_dev_open(dev_list[i], dev_out);
            doca_devinfo_destroy_list(dev_list);
            return ret;
        }
    }

    doca_devinfo_destroy_list(dev_list);
    return DOCA_ERROR_NOT_FOUND;
}

int main(int argc, char **argv)
{
    BenchCli cli{};
    struct doca_dev *dev = nullptr;
    struct doca_dpa *dpa = nullptr;
    GrpcProtoRuntime rt{};
    GrpcOffloadBenchConfig cfg{};
    GrpcOffloadBenchStats stats{};
    doca_error_t ret;

    if (!parse_cli(argc, argv, &cli)) {
        print_usage(argv[0]);
        return 2;
    }

    ret = open_dev_by_pci(cli.pci_addr, &dev);
    if (ret != DOCA_SUCCESS) {
        std::fprintf(stderr, "Failed to open device %s: %s\\n", cli.pci_addr, doca_error_get_name(ret));
        return 1;
    }

    ret = doca_dpa_create(dev, &dpa);
    if (ret != DOCA_SUCCESS) {
        std::fprintf(stderr, "doca_dpa_create failed: %s\\n", doca_error_get_name(ret));
        doca_dev_close(dev);
        return 1;
    }

    ret = doca_dpa_set_app(dpa, DPU_mesh_dpa_app);
    if (ret != DOCA_SUCCESS) {
        std::fprintf(stderr, "doca_dpa_set_app failed: %s\\n", doca_error_get_name(ret));
        doca_dpa_destroy(dpa);
        doca_dev_close(dev);
        return 1;
    }

    ret = doca_dpa_start(dpa);
    if (ret != DOCA_SUCCESS) {
        std::fprintf(stderr, "doca_dpa_start failed: %s\\n", doca_error_get_name(ret));
        doca_dpa_destroy(dpa);
        doca_dev_close(dev);
        return 1;
    }

    ret = grpc_proto_runtime_init(&rt, dpa, nullptr, cli.max_batch);
    if (ret != DOCA_SUCCESS) {
        std::fprintf(stderr, "grpc_proto_runtime_init failed: %s\\n", doca_error_get_name(ret));
        doca_dpa_stop(dpa);
        doca_dpa_destroy(dpa);
        doca_dev_close(dev);
        return 1;
    }

    cfg.warmup_iters = cli.warmup;
    cfg.measure_iters = cli.iters;
    cfg.submit_batch_size = cli.submit_batch;
    cfg.name_len = cli.name_len;
    cfg.scores_count = cli.scores_count;
    cfg.score_seed = cli.score_seed;

    ret = grpc_proto_run_simple_benchmark(&rt, &cfg, &stats);
    grpc_proto_print_benchmark_report(&cfg, &stats);

    grpc_proto_runtime_destroy(&rt);
    (void)doca_dpa_stop(dpa);
    (void)doca_dpa_destroy(dpa);
    (void)doca_dev_close(dev);

    return (ret == DOCA_SUCCESS) ? 0 : 1;
}
